import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.B3IQijK_.js";const u=JSON.parse('{"title":"LLM Setup","description":"Give tradecli access to a large language model — interactively via tradecli setup (API keys) or via /login (OAuth).","frontmatter":{"title":"LLM Setup","description":"Give tradecli access to a large language model — interactively via tradecli setup (API keys) or via /login (OAuth).","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/getting-started/llm-setup"}]]},"headers":[],"relativePath":"getting-started/llm-setup.md","filePath":"getting-started/llm-setup.md"}'),s={name:"getting-started/llm-setup.md"};function r(n,e,d,l,h,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="llm-setup" tabindex="-1">LLM Setup <a class="header-anchor" href="#llm-setup" aria-label="Permalink to &quot;LLM Setup&quot;">​</a></h1><p><code>tradecli</code> needs to talk to a large language model to drive its personas. There are two ways to give it access depending on what you have:</p><table tabindex="0"><thead><tr><th>You have…</th><th>Use…</th></tr></thead><tbody><tr><td>An API key from any supported provider</td><td><code>tradecli setup</code> (interactive wizard)</td></tr><tr><td>A Claude Pro/Max subscription, ChatGPT Plus, GitHub Copilot, or Google AI subscription</td><td><code>/login</code> (OAuth, browser-based)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">One-time setup</p><p>You only need to do this once. After credentials are saved, every future <code>tradecli</code> invocation picks them up automatically — no env vars to remember, no flags to pass.</p></div><h2 id="api-key-path-tradecli-setup" tabindex="-1">API key path: <code>tradecli setup</code> <a class="header-anchor" href="#api-key-path-tradecli-setup" aria-label="Permalink to &quot;API key path: `tradecli setup`&quot;">​</a></h2><p>The simplest path. If you have an API key from Anthropic, OpenAI, Google, or any other supported provider, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span></code></pre></div><p>The wizard&#39;s first step checks whether any credentials are already configured (env vars, an existing <code>~/.tradecli/agent/auth.json</code>). If none are found, it opens an interactive picker:</p><ol><li><strong>Choose an LLM provider</strong> — pick from the list (see <a href="#supported-providers">supported providers</a> below).</li><li><strong>Paste your API key</strong> — input is masked. Press Enter to save.</li><li><strong>Done</strong> — the wizard verifies the credential landed on disk and continues with the rest of setup (browser config, broker auth, etc.).</li></ol><p>Credentials are stored at <code>~/.tradecli/agent/auth.json</code> with <code>0600</code> permissions.</p><h3 id="supported-providers" tabindex="-1">Supported providers <a class="header-anchor" href="#supported-providers" aria-label="Permalink to &quot;Supported providers&quot;">​</a></h3><p>The wizard offers these 9 providers. Each can be configured via the wizard (paste a key) or via environment variable.</p><table tabindex="0"><thead><tr><th>Provider</th><th>Env variable</th><th>Get an API key</th></tr></thead><tbody><tr><td>Anthropic</td><td><code>ANTHROPIC_API_KEY</code></td><td><a href="https://console.anthropic.com/" target="_blank" rel="noreferrer">console.anthropic.com</a></td></tr><tr><td>OpenAI</td><td><code>OPENAI_API_KEY</code></td><td><a href="https://platform.openai.com/api-keys" target="_blank" rel="noreferrer">platform.openai.com</a></td></tr><tr><td>Google (Gemini)</td><td><code>GEMINI_API_KEY</code></td><td><a href="https://aistudio.google.com/apikey" target="_blank" rel="noreferrer">aistudio.google.com</a></td></tr><tr><td>Groq</td><td><code>GROQ_API_KEY</code></td><td><a href="https://console.groq.com/keys" target="_blank" rel="noreferrer">console.groq.com</a></td></tr><tr><td>xAI</td><td><code>XAI_API_KEY</code></td><td><a href="https://console.x.ai/" target="_blank" rel="noreferrer">console.x.ai</a></td></tr><tr><td>OpenRouter</td><td><code>OPENROUTER_API_KEY</code></td><td><a href="https://openrouter.ai/keys" target="_blank" rel="noreferrer">openrouter.ai</a></td></tr><tr><td>Mistral</td><td><code>MISTRAL_API_KEY</code></td><td><a href="https://console.mistral.ai/api-keys" target="_blank" rel="noreferrer">console.mistral.ai</a></td></tr><tr><td>Cerebras</td><td><code>CEREBRAS_API_KEY</code></td><td><a href="https://cloud.cerebras.ai/" target="_blank" rel="noreferrer">cloud.cerebras.ai</a></td></tr><tr><td>HuggingFace</td><td><code>HF_TOKEN</code></td><td><a href="https://huggingface.co/settings/tokens" target="_blank" rel="noreferrer">huggingface.co/settings/tokens</a></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Env vars still work</p><p>If you prefer keeping keys in your shell rc (<code>~/.zshrc</code>, <code>~/.bashrc</code>), <code>export ANTHROPIC_API_KEY=sk-ant-…</code> (or any other provider&#39;s env var) before running <code>tradecli setup</code> — the wizard detects the env var and skips the picker.</p></div><div class="warning custom-block"><p class="custom-block-title">Do not commit API keys</p><p>Keep keys in your shell rc or in <code>~/.tradecli/agent/auth.json</code> — never commit them to a repository. If a key leaks, rotate it immediately in the relevant provider&#39;s console.</p></div><h2 id="oauth-path-login" tabindex="-1">OAuth path: <code>/login</code> <a class="header-anchor" href="#oauth-path-login" aria-label="Permalink to &quot;OAuth path: `/login`&quot;">​</a></h2><p>If you have a subscription rather than an API key — Claude Pro/Max, ChatGPT Plus, GitHub Copilot, or one of Google&#39;s AI subscriptions — use the <code>/login</code> slash command from inside the running TUI. The setup wizard does not handle OAuth (browser flows aren&#39;t a good fit for a one-shot CLI wizard).</p><p>The flow:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # launches the interactive TUI</span></span></code></pre></div><p>Inside the TUI, type:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/login</span></span></code></pre></div><p>Pick the provider, complete the browser login, and the credentials are written to <code>~/.tradecli/agent/auth.json</code> — the same file the wizard uses, so the rest of setup can pick them up.</p><h3 id="supported-oauth-providers" tabindex="-1">Supported OAuth providers <a class="header-anchor" href="#supported-oauth-providers" aria-label="Permalink to &quot;Supported OAuth providers&quot;">​</a></h3><p>Five OAuth providers are available via <code>/login</code>:</p><table tabindex="0"><thead><tr><th>Provider</th><th>What it actually is</th><th>Subscription needed</th></tr></thead><tbody><tr><td>Anthropic</td><td>Claude Pro/Max chat (uses your subscription quota)</td><td>Pro/Max</td></tr><tr><td>ChatGPT (Codex)</td><td>OpenAI&#39;s ChatGPT — separate from the OpenAI API</td><td>ChatGPT Plus / Pro / Team</td></tr><tr><td>GitHub Copilot</td><td>Copilot&#39;s chat completions endpoint</td><td>Copilot Individual / Business</td></tr><tr><td>Google Antigravity</td><td>Google&#39;s coding-focused product</td><td>Antigravity access</td></tr><tr><td>Google Gemini CLI</td><td>Gemini&#39;s CLI-tier auth</td><td>Google account</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">ChatGPT ≠ OpenAI API, Copilot ≠ OpenAI API</p><p>The OAuth-only products are different services from the standard provider APIs in the wizard. ChatGPT (via OAuth) hits OpenAI&#39;s chat endpoints with your subscription quota; the OpenAI API key in the wizard hits the developer endpoints with metered billing. They&#39;re not interchangeable. Pick the one that matches what you&#39;re paying for.</p></div><h2 id="first-run-recipes" tabindex="-1">First-run recipes <a class="header-anchor" href="#first-run-recipes" aria-label="Permalink to &quot;First-run recipes&quot;">​</a></h2><h3 id="i-have-an-api-key-most-common" tabindex="-1">&quot;I have an API key&quot; (most common) <a class="header-anchor" href="#i-have-an-api-key-most-common" aria-label="Permalink to &quot;&quot;I have an API key&quot; (most common)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Pick a provider in the wizard, paste your key, done.</span></span></code></pre></div><p>One command. The wizard runs <code>setup</code> end-to-end including LLM auth.</p><h3 id="i-have-an-anthropic-pro-max-or-any-other-subscription" tabindex="-1">&quot;I have an Anthropic Pro/Max (or any other subscription)&quot; <a class="header-anchor" href="#i-have-an-anthropic-pro-max-or-any-other-subscription" aria-label="Permalink to &quot;&quot;I have an Anthropic Pro/Max (or any other subscription)&quot;&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 1. launch the TUI</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/login</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 2. inside the TUI: pick Anthropic, complete browser login, then quit</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # 3. re-run setup — finds the OAuth credential and continues</span></span></code></pre></div><p>Three commands the first time, one command thereafter.</p><h2 id="after-authentication" tabindex="-1">After authentication <a class="header-anchor" href="#after-authentication" aria-label="Permalink to &quot;After authentication&quot;">​</a></h2><p>Verify the credential is detected:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tradecli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>Look for the <code>llm-auth</code> row:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✓ llm-auth         Anthropic (auth.json)</span></span></code></pre></div><p>The detail in parentheses tells you which source the credential came from — <code>auth.json</code> (wizard or <code>/login</code>), <code>env: ANTHROPIC_API_KEY</code> (env var), or <code>OAuth</code> (OAuth credential in auth.json).</p><p>If the row is <code>✗ llm-auth no providers configured</code>, neither the wizard nor <code>/login</code> has been run yet — go back to the <a href="#api-key-path-tradecli-setup">API key path</a> or the <a href="#oauth-path-login">OAuth path</a> above.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>The wizard says &quot;no LLM provider configured&quot; but I have <code>ANTHROPIC_API_KEY</code> set.</strong></p><p>Check that the env var is exported in the shell that&#39;s running tradecli:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ANTHROPIC_API_KEY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span></span></code></pre></div><p>If the value is empty, your <code>~/.zshrc</code> / <code>~/.bashrc</code> export isn&#39;t being picked up. Open a fresh terminal or <code>source</code> the rc file.</p><p><strong>OAuth login in the browser fails or the page shows an error.</strong></p><p>For Anthropic specifically, the SDK&#39;s local callback server doesn&#39;t always settle cleanly when the browser returns an error. If <code>/login</code> hangs after a browser error, press <code>Esc</code> to cancel — the prompt should release. Then start over.</p><p><strong>I want to switch providers or remove a saved credential.</strong></p><p>Edit <code>~/.tradecli/agent/auth.json</code> directly (it&#39;s a small JSON file keyed by provider id) or, for OAuth credentials, type <code>/logout</code> inside the TUI to open a picker of currently-logged-in OAuth providers.</p><p><strong>I&#39;m on a remote box (SSH&#39;d in) and the OAuth browser flow can&#39;t open.</strong></p><p>The OAuth flow prints a URL you can open on your local machine. After completing login locally, the redirect URL can be pasted back into the prompt. If the local callback server can&#39;t reach you (firewall, no port forward), this is the manual fallback.</p><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><p>Once your LLM credential is configured:</p><ul><li><strong>Connect your broker</strong> → <a href="./broker-setup">Broker Setup</a> — Groww and Zerodha Kite OAuth flows</li><li><strong>Configure the browser</strong> → <a href="./browser-setup">Browser Setup</a> — Chrome CDP for platform automation</li><li><strong>Pick a persona</strong> → <a href="./../guides/personas">Personas guide</a> — what each persona does and when to use it</li></ul><div class="danger custom-block"><p class="custom-block-title">Not financial advice</p><p><code>tradecli</code> is an educational and analytical tool. Nothing it outputs constitutes a recommendation to buy, sell, or hold any security. Always verify AI outputs against primary sources before trading real capital.</p></div>',55)])])}const g=t(s,[["render",r]]);export{u as __pageData,g as default};
